const CONFIG_PATH = 'config/journalism.json';
const formSubmission = $('On form submission').first().json;
const industryConfig = $input.first()?.json?.config;

if (!industryConfig || typeof industryConfig !== 'object' || Array.isArray(industryConfig)) {
  throw new Error('Industry config file could not be parsed from ' + CONFIG_PATH + '. Confirm the file exists and contains valid JSON.');
}

if (!Array.isArray(industryConfig.focus_rotation) || industryConfig.focus_rotation.length === 0) {
  throw new Error('Industry config must define a non-empty focus_rotation array.');
}

const pickFirstString = (...values) => {
  for (const value of values) {
    if (typeof value === 'string' && value.trim().length > 0) {
      return value.trim();
    }
  }
  return '';
};

const slugify = (value) => String(value || '')
  .toLowerCase()
  .trim()
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/(^-|-$)/g, '');

const normalizeToken = (value) => value
  .toLowerCase()
  .replace(/[^a-z0-9]+/g, '')
  .replace(/(ing|ers|ies|ied|er|ed|es|s)$/i, '');

const tokenize = (value) => Array.from(new Set(
  String(value || '')
    .split(/[^A-Za-z0-9]+/)
    .map(normalizeToken)
    .filter((token) => token.length >= 3),
));

const unique = (values) => Array.from(new Set(values.filter((value) => typeof value === 'string' && value.trim().length > 0)));

const suggestedFocusLabel = pickFirstString(
  formSubmission.suggestedFocus,
  formSubmission['Suggested focus'],
  formSubmission.suggested_focus,
);
const customFocus = pickFirstString(
  formSubmission.customFocus,
  formSubmission['Custom focus override'],
  formSubmission.custom_focus,
);
const userContext = pickFirstString(
  formSubmission.userContext,
  formSubmission['Context and hunches'],
  formSubmission.user_context,
);

const selectedFocus = industryConfig.focus_rotation.find((focus) => focus.label === suggestedFocusLabel)
  ?? industryConfig.focus_rotation.find((focus) => focus.slug === slugify(suggestedFocusLabel));

if (!selectedFocus) {
  throw new Error('Suggested focus "' + (suggestedFocusLabel || '(empty)') + '" does not match any focus in the loaded industry config.');
}

const focusWasCustom = customFocus.length > 0;
const customFocusKeywords = focusWasCustom ? unique([customFocus, ...tokenize(customFocus)]) : [];
const anchorKeywords = Array.isArray(selectedFocus.keywords) ? selectedFocus.keywords : [];
const focusKeywords = unique([...customFocusKeywords, ...anchorKeywords]);

const selectedSources = Array.isArray(industryConfig.sources)
  ? industryConfig.sources.filter((source) => {
      const focusAreas = Array.isArray(source.focus_areas) ? source.focus_areas : [];
      return focusAreas.includes('all') || focusAreas.includes(selectedFocus.slug);
    })
  : [];
const selectedRssSources = selectedSources.filter((source) => source.type === 'rss' && typeof source.url === 'string' && source.url.trim().length > 0);
const deferredSources = selectedSources.filter((source) => source.type !== 'rss');

if (selectedRssSources.length === 0) {
  throw new Error('No RSS sources found for focus anchor ' + selectedFocus.slug + '.');
}

return [
  {
    json: {
      run_context: {
        industry_slug: industryConfig.industry,
        industry_label: industryConfig.label,
        focus_slug: focusWasCustom ? slugify(customFocus) : selectedFocus.slug,
        focus_label: focusWasCustom ? customFocus : selectedFocus.label,
        focus_anchor_slug: selectedFocus.slug,
        focus_anchor_label: selectedFocus.label,
        focus_was_custom: focusWasCustom,
        week_number: selectedFocus.week,
        user_context: userContext,
        lookback_days: industryConfig.lookback_days,
        submitted_at: formSubmission.submittedAt ?? null,
      },
      industry_config: industryConfig,
      industry_config_source: {
        mode: 'file',
        path_hint: CONFIG_PATH,
      },
      available_focus_options: industryConfig.focus_rotation.map((focus) => ({
        week: focus.week,
        slug: focus.slug,
        label: focus.label,
      })),
      focus_keywords: focusKeywords,
      selected_sources: selectedSources,
      selected_rss_sources: selectedRssSources,
      deferred_sources: deferredSources,
      deferred_source_types: unique(deferredSources.map((source) => source.type || 'unknown')),
      form_submission: formSubmission,
    },
  },
];

return $json.selected_rss_sources.map((source) => ({
  json: {
    source_name: source.name,
    source_type: source.type,
    source_url: source.url,
    focus_areas: source.focus_areas,
  },
}));

const sourceItems = $('Prepare RSS Sources').all();
const maxIntermediateContentLength = 6000;

const normalizePublishedAt = (value) => {
  if (!value) {
    return null;
  }

  const parsed = new Date(value);
  return Number.isNaN(parsed.getTime()) ? null : parsed.toISOString();
};

const stripHtml = (value) => value.replace(/<[^>]+>/g, ' ');
const normalizeWhitespace = (value) => value.replace(/\s+/g, ' ').trim();
const toPlainText = (value) => normalizeWhitespace(stripHtml(typeof value === 'string' ? value : ''));
const truncateContent = (value, maxLength) => {
  if (value.length <= maxLength) {
    return { text: value, truncated: false };
  }

  const ellipsis = '...';
  if (maxLength <= ellipsis.length) {
    return {
      text: ellipsis.slice(0, maxLength),
      truncated: true,
    };
  }

  return {
    text: value.slice(0, maxLength - ellipsis.length).trimEnd() + ellipsis,
    truncated: true,
  };
};

const normalizeHostname = (value) => {
  const raw = String(value || '').trim();

  if (raw.length === 0) {
    return null;
  }

  const withoutProtocol = raw
    .replace(/^[a-z]+:\/\//i, '')
    .replace(/^\/\//, '');
  const host = withoutProtocol
    .split('/')[0]
    .split('?')[0]
    .split('#')[0]
    .trim()
    .replace(/:\d+$/, '')
    .replace(/^www\./i, '')
    .toLowerCase();

  if (!host || /\s/.test(host) || !host.includes('.')) {
    return null;
  }

  return host;
};

const getPairedItemIndex = (pairedItem) => {
  if (typeof pairedItem === 'number') {
    return pairedItem;
  }

  if (Array.isArray(pairedItem)) {
    for (const candidate of pairedItem) {
      const index = getPairedItemIndex(candidate);
      if (typeof index === 'number') {
        return index;
      }
    }
    return null;
  }

  if (pairedItem && typeof pairedItem.item === 'number') {
    return pairedItem.item;
  }

  return null;
};

return $input.all()
  .flatMap((item) => {
    if (item.json?.error) {
      return [];
    }

    const pairedItemIndex = getPairedItemIndex(item.pairedItem);
    const source = typeof pairedItemIndex === 'number'
      ? sourceItems[pairedItemIndex]?.json
      : null;

    if (!source) {
      return [];
    }

    const title = toPlainText(item.json.title) || 'Untitled feed item';
    const rawContent = item.json.contentSnippet ?? item.json.content ?? item.json.summary ?? item.json.description ?? '';
    const plainTextContent = toPlainText(rawContent);
    const truncated = truncateContent(plainTextContent, maxIntermediateContentLength);
    const articleUrl = item.json.link ?? item.json.guid ?? source.source_url;
    const articleHost = normalizeHostname(articleUrl);
    const feedHost = normalizeHostname(source.source_url);
    const isFeedLinkout = Boolean(articleHost && feedHost && articleHost !== feedHost);
    const sourceName = isFeedLinkout ? articleHost + ' via ' + source.source_name : source.source_name;

    return [{
      json: {
        source_name: sourceName,
        source_type: source.source_type,
        source_url: articleUrl,
        feed_source_name: source.source_name,
        feed_source_url: source.source_url,
        article_source_host: articleHost,
        source_attribution: isFeedLinkout ? 'feed-linkout' : 'feed-origin',
        title,
        content_input: truncated.text,
        content_input_truncated: truncated.truncated,
        published_at: normalizePublishedAt(item.json.isoDate ?? item.json.pubDate ?? null),
      },
    }];
  });

const workflowState = $('Build Run Context').first().json;
const runContext = workflowState.run_context;
const industryConfig = workflowState.industry_config;
const selectedRssSources = workflowState.selected_rss_sources;
const selectedSources = workflowState.selected_sources;
const deferredSources = workflowState.deferred_sources;
const focusKeywords = Array.isArray(workflowState.focus_keywords) ? workflowState.focus_keywords : [];
const maxContentLength = 4000;
const maxLiveSourceItems = 6;
const maxSourceCandidates = 20;
const relevanceThreshold = 5;
const weakKeywordTokensRaw = ['editor', 'editorial', 'journal', 'journalist', 'media', 'news', 'newsroom', 'publish'];
const stopwordsRaw = ['about', 'after', 'again', 'against', 'being', 'below', 'between', 'during', 'editors', 'their', 'there', 'these', 'those', 'under', 'where', 'which', 'while', 'would', 'keeps'];
const lookbackDays = Number(runContext.lookback_days) || 0;
const lookbackCutoff = lookbackDays > 0
  ? new Date(Date.now() - lookbackDays * 24 * 60 * 60 * 1000)
  : null;

const isWithinLookback = (publishedAt) => {
  if (!lookbackCutoff) {
    return true;
  }

  if (!publishedAt) {
    return false;
  }

  return new Date(publishedAt).getTime() >= lookbackCutoff.getTime();
};

const truncateContent = (value, maxLength) => {
  if (value.length <= maxLength) {
    return { text: value, truncated: false };
  }

  const ellipsis = '...';
  if (maxLength <= ellipsis.length) {
    return {
      text: ellipsis.slice(0, maxLength),
      truncated: true,
    };
  }

  return {
    text: value.slice(0, maxLength - ellipsis.length).trimEnd() + ellipsis,
    truncated: true,
  };
};

const normalizeToken = (value) => value
  .toLowerCase()
  .replace(/[^a-z0-9]+/g, '')
  .replace(/(ing|ers|ies|ied|er|ed|es|s)$/i, '');

const weakKeywordTokens = new Set(weakKeywordTokensRaw.map(normalizeToken));
const stopwords = new Set(stopwordsRaw.map(normalizeToken));

const tokenize = (value) => Array.from(new Set(
  String(value || '')
    .split(/[^A-Za-z0-9]+/)
    .map(normalizeToken)
    .filter((token) => token.length >= 3),
));

const unique = (values) => Array.from(new Set(values));
const focusKeywordPhrases = focusKeywords.map((keyword) => {
  const tokens = tokenize(keyword);
  const strongTokens = tokens.filter((token) => !weakKeywordTokens.has(token));

  return {
    label: keyword,
    normalized: keyword.toLowerCase(),
    tokens,
    strong_tokens: strongTokens,
  };
});
const strongKeywordPhrases = focusKeywordPhrases.filter((keyword) => keyword.strong_tokens.length > 0);
const focusKeywordByLabel = focusKeywordPhrases.reduce((acc, keyword) => {
  acc[keyword.label] = keyword;
  return acc;
}, {});
const contextTokens = tokenize(runContext.user_context || '').filter((token) => token.length >= 5 && !stopwords.has(token));

const normalizedItems = $input.all().map((item, index) => {
  const feedItem = item.json;
  const truncated = truncateContent(feedItem.content_input ?? '', maxContentLength);
  const content = truncated.text;
  const haystack = (String(feedItem.title || '') + ' ' + content).toLowerCase();
  const titleLower = String(feedItem.title || '').toLowerCase();
  const contentLower = content.toLowerCase();

  return {
    id: 'source-' + String(index + 1),
    source_name: feedItem.source_name,
    source_type: feedItem.source_type,
    source_url: feedItem.source_url,
    feed_source_name: feedItem.feed_source_name,
    feed_source_url: feedItem.feed_source_url,
    article_source_host: feedItem.article_source_host,
    source_attribution: feedItem.source_attribution,
    title: feedItem.title,
    title_lower: titleLower,
    content,
    content_lower: contentLower,
    content_truncated: feedItem.content_input_truncated || truncated.truncated,
    published_at: feedItem.published_at,
    matched_keywords: focusKeywords.filter((keyword) => haystack.includes(keyword.toLowerCase())),
  };
});

const lookbackItems = normalizedItems.filter((item) => isWithinLookback(item.published_at));
const candidateItems = lookbackItems.length > 0 ? lookbackItems : normalizedItems;
const scoredItems = candidateItems
  .map((item) => {
    const titleTokens = tokenize(item.title);
    const contentTokens = tokenize(item.content);
    const exactMatches = Array.isArray(item.matched_keywords) ? item.matched_keywords : [];
    const exactStrongMatches = exactMatches.filter((label) => {
      const keyword = focusKeywordByLabel[label];
      return keyword && Array.isArray(keyword.strong_tokens) && keyword.strong_tokens.length > 0;
    });
    const exactWeakOnlyMatches = exactMatches.filter((label) => {
      const keyword = focusKeywordByLabel[label];
      return !keyword || !Array.isArray(keyword.strong_tokens) || keyword.strong_tokens.length === 0;
    });
    const titlePhraseMatches = unique(strongKeywordPhrases.filter((keyword) => item.title_lower.includes(keyword.normalized)).map((keyword) => keyword.label));
    const contentPhraseMatches = unique(strongKeywordPhrases.filter((keyword) => !titlePhraseMatches.includes(keyword.label) && item.content_lower.includes(keyword.normalized)).map((keyword) => keyword.label));
    const titleTokenMatches = unique(strongKeywordPhrases.filter((keyword) => !titlePhraseMatches.includes(keyword.label) && keyword.strong_tokens.some((token) => titleTokens.includes(token))).map((keyword) => keyword.label));
    const contentTokenMatches = unique(strongKeywordPhrases.filter((keyword) => !titlePhraseMatches.includes(keyword.label) && !contentPhraseMatches.includes(keyword.label) && !titleTokenMatches.includes(keyword.label) && keyword.strong_tokens.some((token) => contentTokens.includes(token))).map((keyword) => keyword.label));
    const contextMatches = unique(contextTokens.filter((token) => titleTokens.includes(token) || contentTokens.includes(token)));
    const strongSignalCount = exactStrongMatches.length + titlePhraseMatches.length + contentPhraseMatches.length + titleTokenMatches.length + contentTokenMatches.length;
    const relevanceScore = (exactStrongMatches.length * 7) + (titlePhraseMatches.length * 6) + (contentPhraseMatches.length * 4) + (titleTokenMatches.length * 3) + (contentTokenMatches.length * 2) + (contextMatches.length);
    const relevanceBand = relevanceScore >= 8 ? 'high' : relevanceScore >= relevanceThreshold ? 'medium' : relevanceScore > 0 ? 'low' : 'none';

    return {
      ...item,
      relevance_score: relevanceScore,
      relevance_band: relevanceBand,
      strong_signal_count: strongSignalCount,
      relevance_signals: {
        exact_focus_matches: exactMatches,
        exact_focus_matches_strong: exactStrongMatches,
        exact_focus_matches_weak_only: exactWeakOnlyMatches,
        title_phrase_matches: titlePhraseMatches,
        content_phrase_matches: contentPhraseMatches,
        title_token_matches: titleTokenMatches,
        content_token_matches: contentTokenMatches,
        context_matches: contextMatches,
      },
    };
  })
  .sort((left, right) => {
    if (right.relevance_score !== left.relevance_score) {
      return right.relevance_score - left.relevance_score;
    }

    return String(right.published_at || '').localeCompare(String(left.published_at || ''));
  });

const sourceCandidates = scoredItems.slice(0, maxSourceCandidates).map((candidate) => ({
  id: candidate.id,
  source_name: candidate.source_name,
  source_type: candidate.source_type,
  source_url: candidate.source_url,
  feed_source_name: candidate.feed_source_name,
  feed_source_url: candidate.feed_source_url,
  article_source_host: candidate.article_source_host,
  source_attribution: candidate.source_attribution,
  title: candidate.title,
  published_at: candidate.published_at,
  matched_keywords: candidate.matched_keywords,
  relevance_score: candidate.relevance_score,
  relevance_band: candidate.relevance_band,
  strong_signal_count: candidate.strong_signal_count,
  relevance_signals: candidate.relevance_signals,
}));

const thresholdSources = scoredItems.filter((item) => item.strong_signal_count > 0 && item.relevance_score >= relevanceThreshold).slice(0, maxLiveSourceItems).map(({ title_lower, content_lower, ...item }) => item);
const lowConfidenceSources = scoredItems.filter((item) => item.strong_signal_count > 0 && item.relevance_score > 0 && item.relevance_score < relevanceThreshold).slice(0, 2).map(({ title_lower, content_lower, ...item }) => item);
const sourceBatch = thresholdSources.length > 0 ? thresholdSources : lowConfidenceSources;
const sourceSelectionMode = thresholdSources.length > 0 ? 'threshold' : sourceBatch.length > 0 ? 'fallback-low-confidence' : 'none';
const contributingSourceCount = new Set(normalizedItems.map((item) => item.feed_source_url)).size;

const deferredSourceNote = deferredSources.length > 0
  ? String(deferredSources.length) + ' configured non-RSS sources were deferred in this slice.'
  : 'No non-RSS sources were selected for this run.';
const sourceIngestionNote = lookbackItems.length > 0
  ? 'Source batch built from ' + String(contributingSourceCount) + ' of ' + String(selectedRssSources.length) + ' configured RSS sources within the lookback window. ' + deferredSourceNote + ' Content is normalized to plain text and bounded for prompt use.'
  : 'No live RSS items fell within the configured lookback window, so the workflow used the latest normalized feed items as candidates. ' + deferredSourceNote;

const sourceSelectionNote = sourceSelectionMode === 'threshold'
  ? 'Selected ' + String(sourceBatch.length) + ' of ' + String(scoredItems.length) + ' candidate source documents for live pass-1 extraction after focus relevance scoring.'
  : sourceSelectionMode === 'fallback-low-confidence'
    ? 'No candidate source documents met the primary relevance threshold, so the workflow kept ' + String(sourceBatch.length) + ' low-confidence items with partial focus overlap for manual review.'
    : 'No candidate source documents met the current focus relevance threshold, so live pass-1 extraction is skipped and downstream extraction nodes do not run for this execution.';

return [
  {
    json: {
      run_context: runContext,
      industry_config: industryConfig,
      industry_config_source: workflowState.industry_config_source,
      available_focus_options: workflowState.available_focus_options,
      form_submission: workflowState.form_submission,
      selected_sources: selectedSources,
      selected_rss_sources: selectedRssSources,
      deferred_sources: deferredSources,
      deferred_source_types: workflowState.deferred_source_types,
      focus_keywords: focusKeywords,
      lookback_cutoff: lookbackCutoff ? lookbackCutoff.toISOString() : null,
      contributing_source_count: contributingSourceCount,
      source_ingestion_note: sourceIngestionNote,
      source_selection_mode: sourceSelectionMode,
      source_selection_note: sourceSelectionNote,
      selected_source_count: sourceBatch.length,
      source_candidates: sourceCandidates,
      source_batch: sourceBatch,
    },
  },
];

const templateRef = 'n8n/prompts/pass-1-extraction.md';
const runContext = $json.run_context;
const sourceBatch = $json.source_batch;

const buildPrompt = (source) => {
  const lines = [
    'System: You are analyzing content from ' + runContext.industry_label + ' industry sources.',
    'This week\'s focus: ' + runContext.focus_label + '.',
  ];

  if (runContext.user_context) {
    lines.push(
      'The person running this analysis added the following context',
      'and hunches to guide your attention: "' + runContext.user_context + '"',
      'Weight pain points related to their observations more heavily.',
    );
  }

  lines.push(
    '',
    'Extract any professional pain points, unmet needs, or recurring',
    'frustrations mentioned or implied. Return JSON only.',
    '',
    '{',
    '  "pain_points": [',
    '    {',
    '      "description": "string - the pain point in plain language",',
    '      "who_feels_it": "string - which role or group",',
    '      "evidence_quote": "string - short supporting excerpt",',
    '      "severity": "low | medium | high"',
    '    }',
    '  ],',
    '  "source_summary": "string - 1-2 sentence summary of the source content"',
    '}',
    '',
    'If no pain points are present, return {"pain_points": [], "source_summary": "..."}',
    '',
    'Source title: ' + source.title,
    'Source content: ' + source.content,
  );

  return lines.join('\n');
};

const extractionRequests = sourceBatch.map((source) => ({
  source_id: source.id,
  source_name: source.source_name,
  source_url: source.source_url,
  source_type: source.source_type,
  feed_source_name: source.feed_source_name,
  feed_source_url: source.feed_source_url,
  article_source_host: source.article_source_host,
  source_attribution: source.source_attribution,
  prompt_template_ref: templateRef,
  rendered_prompt: buildPrompt(source),
  source_document: source,
}));

return [
  {
    json: {
      ...$json,
      extraction_requests: extractionRequests,
    },
  },
];

const preferredModel = 'gemini-3.1-flash-lite-preview';
const fallbackModel = 'gemini-2.5-flash-lite';
const extractionSchema = {
  type: 'object',
  properties: {
    pain_points: {
      type: 'array',
      items: {
        type: 'object',
        properties: {
          description: { type: 'string' },
          who_feels_it: { type: 'string' },
          evidence_quote: { type: 'string' },
          severity: {
            type: 'string',
            enum: ['low', 'medium', 'high']
          }
        },
        required: ['description', 'who_feels_it', 'evidence_quote', 'severity']
      }
    },
    source_summary: { type: 'string' }
  },
  required: ['pain_points', 'source_summary']
};

const buildGeminiRequest = (prompt) => ({
  contents: [
    {
      parts: [
        {
          text: prompt
        }
      ]
    }
  ],
  generationConfig: {
    temperature: 0.2,
    responseMimeType: 'application/json',
    responseSchema: extractionSchema
  }
});

return $json.extraction_requests.map((request) => ({
  json: {
    ...request,
    llm_provider: 'gemini',
    preferred_llm_model: preferredModel,
    fallback_llm_model: fallbackModel,
    llm_model: preferredModel,
    gemini_request: buildGeminiRequest(request.rendered_prompt)
  }
}));

const requestItems = $('Prepare Live Pass 1 Calls').all();

const getPairedItemIndex = (pairedItem) => {
  if (typeof pairedItem === 'number') {
    return pairedItem;
  }

  if (Array.isArray(pairedItem)) {
    for (const candidate of pairedItem) {
      const index = getPairedItemIndex(candidate);
      if (typeof index === 'number') {
        return index;
      }
    }
    return null;
  }

  if (pairedItem && typeof pairedItem.item === 'number') {
    return pairedItem.item;
  }

  return null;
};

const toErrorText = (value) => {
  if (typeof value === 'string') {
    return value;
  }

  if (value && typeof value.message === 'string') {
    return value.message;
  }

  try {
    return JSON.stringify(value);
  } catch (error) {
    return String(value);
  }
};

const fallbackRequests = $input.all().flatMap((item, index) => {
  if (!item.json?.error) {
    return [];
  }

  const pairedItemIndex = getPairedItemIndex(item.pairedItem);
  const requestIndex = typeof pairedItemIndex === 'number' ? pairedItemIndex : index;
  const request = requestItems[requestIndex]?.json;

  if (!request) {
    return [];
  }

  return [{
    json: {
      ...request,
      llm_model: request.fallback_llm_model,
      fallback_from_model: request.preferred_llm_model,
      primary_error: toErrorText(item.json.error),
      should_fallback: true,
    },
    pairedItem: { item: requestIndex },
  }];
});

if (fallbackRequests.length > 0) {
  return fallbackRequests;
}

return [
  {
    json: {
      should_fallback: false,
      fallback_reason: 'Primary Gemini responses all succeeded.',
    },
    pairedItem: { item: 0 },
  },
];

const requestItems = $('Prepare Live Pass 1 Calls').all();
const primaryResponses = $('Gemini Pass 1 Extraction').all();
const fallbackResponses = $('Gemini Fallback Extraction').all();

const getPairedItemIndex = (pairedItem) => {
  if (typeof pairedItem === 'number') {
    return pairedItem;
  }

  if (Array.isArray(pairedItem)) {
    for (const candidate of pairedItem) {
      const index = getPairedItemIndex(candidate);
      if (typeof index === 'number') {
        return index;
      }
    }
    return null;
  }

  if (pairedItem && typeof pairedItem.item === 'number') {
    return pairedItem.item;
  }

  return null;
};

const toErrorText = (value) => {
  if (typeof value === 'string') {
    return value;
  }

  if (value && typeof value.message === 'string') {
    return value.message;
  }

  try {
    return JSON.stringify(value);
  } catch (error) {
    return String(value);
  }
};

const mapResponsesByIndex = (items) => {
  const mapped = new Map();

  for (const item of items) {
    const pairedItemIndex = getPairedItemIndex(item.pairedItem);

    if (typeof pairedItemIndex === 'number') {
      mapped.set(pairedItemIndex, item.json);
    }
  }

  return mapped;
};

const primaryByIndex = mapResponsesByIndex(primaryResponses);
const fallbackByIndex = mapResponsesByIndex(fallbackResponses);

return requestItems.map((requestItem, index) => {
  const request = requestItem.json;
  const primaryResponse = primaryByIndex.get(index);
  const fallbackResponse = fallbackByIndex.get(index);

  if (primaryResponse && !primaryResponse.error) {
    return {
      json: {
        ...primaryResponse,
        __request_context: {
          ...request,
          llm_model: request.preferred_llm_model,
          resolved_llm_model: request.preferred_llm_model,
          fallback_used: false,
        },
      },
      pairedItem: { item: index },
    };
  }

  if (fallbackResponse && !fallbackResponse.error) {
    return {
      json: {
        ...fallbackResponse,
        __request_context: {
          ...request,
          llm_model: request.fallback_llm_model,
          resolved_llm_model: request.fallback_llm_model,
          fallback_used: true,
        },
      },
      pairedItem: { item: index },
    };
  }

  const primaryError = primaryResponse?.error ? toErrorText(primaryResponse.error) : 'No response from primary model.';
  const fallbackError = fallbackResponse?.error ? toErrorText(fallbackResponse.error) : 'Fallback model was not attempted.';

  throw new Error(
    `Gemini pass-1 extraction failed for source_id=${request.source_id || 'unknown'} ` +
    `source_url=${request.source_url || 'unknown'} primary_model=${request.preferred_llm_model} primary_error=${primaryError} ` +
    `fallback_model=${request.fallback_llm_model} fallback_error=${fallbackError}.`,
  );
});

const requestItems = $('Prepare Live Pass 1 Calls').all();

const getResponseText = (response) => {
  const candidates = Array.isArray(response.candidates) ? response.candidates : [];

  for (const candidate of candidates) {
    const parts = candidate?.content?.parts;

    if (!Array.isArray(parts)) {
      continue;
    }

    for (const part of parts) {
      if (typeof part?.text === 'string') {
        return part.text;
      }
    }
  }

  throw new Error('Gemini pass-1 response did not include structured text output.');
};

return $input.all().map((item, index) => {
  const responsePayload = { ...item.json };
  const request = responsePayload.__request_context ?? requestItems[index]?.json;
  delete responsePayload.__request_context;

  if (!request) {
    throw new Error(`Missing request context for Gemini response index ${index}.`);
  }

  let responseText;
  try {
    responseText = getResponseText(responsePayload);
  } catch (error) {
    let rawResponseSnippet = '';

    try {
      rawResponseSnippet = JSON.stringify(responsePayload).slice(0, 500);
    } catch (stringifyError) {
      rawResponseSnippet = String(responsePayload).slice(0, 500);
    }

    throw new Error(
      `Gemini pass-1 response did not include structured text output for source_id=${request.source_id || 'unknown'} ` +
      `source_url=${request.source_url || 'unknown'} model=${request.resolved_llm_model || request.llm_model || 'unknown'} index=${index}. ` +
      `Underlying error: ${error.message}. Raw response snippet: ${rawResponseSnippet}`,
    );
  }

  let parsed;
  try {
    parsed = JSON.parse(responseText);
  } catch (error) {
    const rawTextSnippet = responseText.slice(0, 500);

    throw new Error(
      `Failed to parse Gemini pass-1 JSON for source_id=${request.source_id || 'unknown'} ` +
      `source_url=${request.source_url || 'unknown'} model=${request.resolved_llm_model || request.llm_model || 'unknown'} index=${index}. ` +
      `Raw text snippet: ${rawTextSnippet}. Error: ${error.message}`,
    );
  }

  const painPoints = Array.isArray(parsed.pain_points) ? parsed.pain_points : [];

  return {
    json: {
      source_id: request.source_id,
      source_name: request.source_name,
      source_url: request.source_url,
      feed_source_name: request.feed_source_name,
      feed_source_url: request.feed_source_url,
      article_source_host: request.article_source_host,
      source_attribution: request.source_attribution,
      source_summary: typeof parsed.source_summary === 'string' ? parsed.source_summary : '',
      pain_points: painPoints.map((painPoint) => ({
        description: painPoint.description,
        who_feels_it: painPoint.who_feels_it,
        evidence_quote: painPoint.evidence_quote,
        severity: painPoint.severity,
      })),
      llm_provider: request.llm_provider,
      llm_model: request.resolved_llm_model || request.llm_model,
      resolved_llm_model: request.resolved_llm_model || request.llm_model,
      preferred_llm_model: request.preferred_llm_model,
      fallback_llm_model: request.fallback_llm_model,
      fallback_used: Boolean(request.fallback_used),
    },
  };
});

const workflowState = $('Build Pass 1 Prompt Payloads').first().json;
const extractionResults = $input.all().map((item) => item.json);
const fallbackUsageCount = extractionResults.filter((result) => result.fallback_used).length;
const resolvedModels = [...new Set(extractionResults.map((result) => result.resolved_llm_model || result.llm_model).filter(Boolean))];
const resolvedModelsLabel = resolvedModels.length > 0 ? resolvedModels.join(', ') : 'none';

return [
